    .{ 0x00, 0x00, 0x0E, 0x1B, 0x1B, 0x18, 0x18, 0x18, 0x18, 0x18, 0x18, 0x18, 0x18, 0x18, 0x18, 0x18 },
    // 0xF5 — ⌡
    .{ 0x18, 0x18, 0x18, 0x18, 0x18, 0x18, 0x18, 0x18, 0x18, 0xD8, 0xD8, 0xD8, 0x70, 0x00, 0x00, 0x00 },
    // 0xF6 — ÷
    .{ 0x00, 0x00, 0x00, 0x00, 0x18, 0x18, 0x00, 0x7E, 0x00, 0x18, 0x18, 0x00, 0x00, 0x00, 0x00, 0x00 },
    // 0xF7 — ≈
    .{ 0x00, 0x00, 0x00, 0x00, 0x00, 0x76, 0xDC, 0x00, 0x76, 0xDC, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00 },
    // 0xF8 — °
    .{ 0x00, 0x38, 0x6C, 0x6C, 0x38, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00 },
    // 0xF9 — ∙
    .{ 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x18, 0x18, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00 },
    // 0xFA — ·
    .{ 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x18, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00 },
    // 0xFB — √
    .{ 0x00, 0x0F, 0x0C, 0x0C, 0x0C, 0x0C, 0x0C, 0xEC, 0x6C, 0x6C, 0x3C, 0x1C, 0x00, 0x00, 0x00, 0x00 },
    // 0xFC — ⁿ
    .{ 0x00, 0xD8, 0x6C, 0x6C, 0x6C, 0x6C, 0x6C, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00 },
    // 0xFD — ²
    .{ 0x00, 0x70, 0xD8, 0x30, 0x60, 0xC8, 0xF8, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00 },
    // 0xFE — ■
    .{ 0x00, 0x00, 0x00, 0x00, 0x3C, 0x3C, 0x3C, 0x3C, 0x3C, 0x3C, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00 },
    // 0xFF — (blank)
    .{ 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00 },
};

// ─── Helper Functions ───────────────────────────────────────────────────────

/// Get a pointer to the glyph bitmap data for a given character and font.
/// Returns a pointer to the first row byte.
///   font_id 0 → 8×8 font
///   font_id 1 → 8×16 font
pub inline fn getGlyph(char_code: u8, font_id: u1) []const u8 {
    return switch (font_id) {
        0 => &font_8x8[char_code],
        1 => &font_8x16[char_code],
    };
}

/// Return the height in pixels for the given font.
pub inline fn getFontHeight(font_id: u1) u32 {
    return switch (font_id) {
        0 => FONT_8X8_HEIGHT,
        1 => FONT_8X16_HEIGHT,
    };
}

/// Check if a pixel is set in a glyph row byte.
/// col 0 = leftmost (MSB), col 7 = rightmost (LSB).
pub inline fn pixelSet(row_byte: u8, col: u3) bool {
    return (row_byte & (@as(u8, 0x80) >> col)) != 0;
}

// ─── Tests ──────────────────────────────────────────────────────────────────

test "font_8x8 has 256 glyphs" {
    try @import("std").testing.expectEqual(@as(usize, 256), font_8x8.len);
}

test "font_8x16 has 256 glyphs" {
    try @import("std").testing.expectEqual(@as(usize, 256), font_8x16.len);
}

test "space glyph is blank (8x8)" {
    const space = font_8x8[0x20];
    for (space) |row| {
        try @import("std").testing.expectEqual(@as(u8, 0), row);
    }
}

test "space glyph is blank (8x16)" {
    const space = font_8x16[0x20];
    for (space) |row| {
        try @import("std").testing.expectEqual(@as(u8, 0), row);
    }
}

test "full block glyph is all 0xFF (8x8)" {
    const block = font_8x8[0xDB];
    for (block) |row| {
        try @import("std").testing.expectEqual(@as(u8, 0xFF), row);
    }
}

test "full block glyph is all 0xFF (8x16)" {
    const block = font_8x16[0xDB];
    for (block) |row| {
        try @import("std").testing.expectEqual(@as(u8, 0xFF), row);
    }
}

test "pixelSet helper" {
    // Row 0xFF: all pixels set
    try @import("std").testing.expect(pixelSet(0xFF, 0));
    try @import("std").testing.expect(pixelSet(0xFF, 7));
    // Row 0x80: only leftmost pixel set
    try @import("std").testing.expect(pixelSet(0x80, 0));
    try @import("std").testing.expect(!pixelSet(0x80, 1));
    // Row 0x01: only rightmost pixel set
    try @import("std").testing.expect(!pixelSet(0x01, 0));
    try @import("std").testing.expect(pixelSet(0x01, 7));
}

test "A glyph (8x8) has non-empty rows" {
    const a_glyph = font_8x8[0x41]; // 'A'
    var non_empty: u32 = 0;
    for (a_glyph) |row| {
        if (row != 0) non_empty += 1;
    }
    // 'A' should have at least 6 non-empty rows
    try @import("std").testing.expect(non_empty >= 6);
}

test "getGlyph returns correct length" {
    const g8 = getGlyph('A', 0);
    try @import("std").testing.expectEqual(@as(usize, 8), g8.len);
    const g16 = getGlyph('A', 1);
    try @import("std").testing.expectEqual(@as(usize, 16), g16.len);
}

test "getFontHeight returns correct values" {
    try @import("std").testing.expectEqual(@as(u32, 8), getFontHeight(0));
    try @import("std").testing.expectEqual(@as(u32, 16), getFontHeight(1));
}
